// evento_id vem do no Claim (pairing de itens preservado).
const eventoId = $('Claim Batch').item.json.evento_id;
const code = $json.statusCode;
const ok = typeof code === 'number' && code >= 200 && code < 300;
let erro = null;
if (!ok) {
  let b = $json.body;
  if (b && typeof b === 'object') b = JSON.stringify(b);
  erro = ('HTTP ' + (code ?? 'sem resposta') + ' ' + (b ?? '')).slice(0, 500);
}
return { json: { evento_id: eventoId, ok, http_status: code ?? null, erro } };
